import { TestingModule } from '@nestjs/testing';
import { DataSource, Repository } from 'typeorm';
import { createIntegrationTestModule, cleanDatabase } from './setup';
import { InventoryReservation } from '../../src/entities/inventory-reservation.entity';
import { buildInventoryReservation } from '../factories/inventory-reservation.factory';
import { Category } from '../../src/entities/category.entity';
import { buildCategory } from '../factories/category.factory';
import { Product } from '../../src/entities/product.entity';
import { buildProduct } from '../factories/product.factory';

describe('InventoryReservation Relationships', () => {
  let module: TestingModule;
  let dataSource: DataSource;
  let repository: Repository<InventoryReservation>;
  let categoryId: string;
  let productId: string;

  beforeAll(async () => {
    module = await createIntegrationTestModule();
    dataSource = module.get(DataSource);
    repository = dataSource.getRepository(InventoryReservation);
  });

  beforeEach(async () => {
    const categoryEntity = await dataSource
      .getRepository(Category)
      .save(
        dataSource.getRepository(Category).create(
          buildCategory(),
        ),
      );
    categoryId = categoryEntity.id;
    const productEntity = await dataSource
      .getRepository(Product)
      .save(
        dataSource.getRepository(Product).create(
          buildProduct({ categoryId: categoryId }),
        ),
      );
    productId = productEntity.id;
  });

  afterEach(async () => {
    await cleanDatabase(dataSource);
  });

  afterAll(async () => {
    await module.close();
  });

  describe('belongs_to Product', () => {
    it('persists productId reference', async () => {
      const data = buildInventoryReservation({ productId: productId });
      const saved = await repository.save(repository.create(data));
      expect(saved.productId).toBe(productId);
    });

    it('loads parent via relation', async () => {
      const data = buildInventoryReservation({ productId: productId });
      const saved = await repository.save(repository.create(data));
      const loaded = await repository.findOne({
        where: { id: saved.id } as Record<string, unknown>,
        relations: ['product'],
      });
      expect(loaded).not.toBeNull();
      expect(loaded!.product).toBeDefined();
      expect(loaded!.product.id).toBe(productId);
    });

    it('rejects entity without required productId', async () => {
      const data = buildInventoryReservation({ productId: undefined as unknown as string });
      await expect(
        repository.save(repository.create(data)),
      ).rejects.toThrow();
    });
  });
});
